"""Tool: LLM-generated Plotly dashboard (step 10 code exec)."""

from __future__ import annotations

import json
import re
import sqlite3
import subprocess
import tempfile
from datetime import datetime, timezone
from pathlib import Path

from fastapi import UploadFile
from langflow.api.v2.files import upload_user_file
from langflow.custom import Component
from langflow.io import MessageTextInput, Output
from langflow.schema import Data
from langflow.services.database.models.user.crud import get_user_by_id
from langflow.services.deps import get_session, get_settings_service, get_storage_service


class CreditDashboardCodeExecTool(Component):
    display_name = "Credit Dashboard Code Exec Tool"
    description = "Runs agent-generated Plotly JS (renderDashboard) and exports HTML + upload."
    icon = "line-chart"
    name = "CreditDashboardCodeExecTool"

    inputs = [
        MessageTextInput(
            name="record_json",
            display_name="Chart Intent",
            info="Short description of what to visualize (for the agent, optional).",
            required=False,
            tool_mode=True,
            value="",
        ),
        MessageTextInput(
            name="chart_code",
            display_name="Chart Code (JS)",
            info=(
                "JavaScript only. Must define: async function renderDashboard(payload, Plotly, containers) { ... }"
            ),
            required=True,
            tool_mode=True,
            value="",
        ),
        MessageTextInput(
            name="snapshot_id",
            display_name="Output Filename",
            info="HTML filename. Default: credit_dashboard_step10.html",
            required=False,
            tool_mode=True,
            advanced=True,
            value="credit_dashboard_step10.html",
        ),
        MessageTextInput(
            name="database_url",
            display_name="Database URL",
            info="SQLite URL like sqlite:////tmp/credit_products.db",
            value="sqlite:////tmp/credit_products.db",
            required=True,
            advanced=True,
        ),
    ]

    outputs = [
        Output(display_name="Dashboard Export", name="export_credit_dashboard", method="export_credit_dashboard"),
    ]

    async def export_credit_dashboard(self) -> Data:
        db_path = self._sqlite_path(self.database_url)
        if not db_path.exists():
            return self._result("error", errors=[f"Database file not found: {db_path}"])

        rows = self._load_rows(db_path)
        if not rows:
            return self._result("error", errors=["No rows found in credit_product_snapshots"])

        code = self._strip_markdown_fences((self.chart_code or "").strip())
        if not code:
            return self._result("invalid_code", errors=["chart_code is empty"])

        validation_errors = self._validate_js_code(code)
        if validation_errors:
            return self._result("invalid_code", errors=validation_errors)

        syntax_ok, syntax_error = self._check_js_syntax(code)
        if not syntax_ok:
            return self._result("invalid_code", errors=[f"JavaScript syntax error: {syntax_error}"])

        filename = self._normalized_filename(self.snapshot_id)
        out_path = self._resolve_output_path(filename)

        payload = self._build_payload(rows)
        html = self._build_html(payload, code)
        out_path.write_text(html, encoding="utf-8")
        await self._upload_file(out_path)

        result = {
            "status": "ok",
            "file_path": str(out_path),
            "rows_used": len(rows),
            "generated_at": datetime.now(timezone.utc).isoformat(),
            "errors": [],
        }
        self.status = result
        return Data(data={"text": json.dumps(result, ensure_ascii=False), **result})

    def _build_payload(self, rows: list[dict]) -> dict:
        normalized_rows = [
            {k: self._normalize_cell(v) for k, v in row.items()}
            for row in rows
        ]
        columns = sorted({key for row in normalized_rows for key in row.keys()})
        sample_rows = normalized_rows[:12]
        profile = {"column_count": len(columns), "columns": columns}

        bank_map: dict[str, dict] = {}
        dates = sorted(
            {
                str(r.get("generated_at"))
                for r in normalized_rows
                if r.get("generated_at") is not None and str(r.get("generated_at")).strip()
            }
        )

        for row in normalized_rows:
            bank = str(row.get("bank") or "").strip()
            date_value = str(row.get("generated_at") or "").strip()
            if not bank or not date_value:
                continue
            if bank not in bank_map:
                bank_map[bank] = {"rate": {}, "max_amount": {}}
            bank_map[bank]["rate"][date_value] = self._extract_percent(row.get("rate"))
            bank_map[bank]["max_amount"][date_value] = self._extract_number(row.get("max_amount"))

        banks = sorted(bank_map.keys())
        traces_rate = []
        traces_amount = []
        summary = []

        for bank in banks:
            y_rate = [bank_map[bank]["rate"].get(d) for d in dates]
            y_amount = [bank_map[bank]["max_amount"].get(d) for d in dates]
            traces_rate.append({"name": bank, "x": dates, "y": y_rate})
            traces_amount.append({"name": bank, "x": dates, "y": y_amount})

            first_rate = next((v for v in y_rate if v is not None), None)
            last_rate = next((v for v in reversed(y_rate) if v is not None), None)
            first_amt = next((v for v in y_amount if v is not None), None)
            last_amt = next((v for v in reversed(y_amount) if v is not None), None)

            summary.append(
                {
                    "bank": bank,
                    "rate_first": first_rate,
                    "rate_last": last_rate,
                    "rate_delta_pp": (last_rate - first_rate)
                    if first_rate is not None and last_rate is not None
                    else None,
                    "amount_first": first_amt,
                    "amount_last": last_amt,
                    "amount_delta": (last_amt - first_amt)
                    if first_amt is not None and last_amt is not None
                    else None,
                }
            )

        return {
            "columns": columns,
            "records": normalized_rows,
            "sample_rows": sample_rows,
            "profile": profile,
            "suggested_charts": [
                {"id": "line_timeseries", "x_hint": "generated_at", "y_hint": "rate", "group_hint": "bank"},
                {"id": "line_amount", "x_hint": "generated_at", "y_hint": "max_amount", "group_hint": "bank"},
                {"id": "bar_compare", "x_hint": "bank", "y_hint": "max_amount", "aggregation": "last"}
            ],
            "dates": dates,
            "traces_rate": traces_rate,
            "traces_amount": traces_amount,
            "summary": summary,
        }

    def _build_html(self, payload: dict, chart_code: str) -> str:
        payload_json = json.dumps(payload, ensure_ascii=False)
        safe_code = chart_code.replace("</script>", "<\\/script>")

        return f"""<!doctype html>
<html lang="ru">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Credit Dashboard (LLM Codegen)</title>
  <script src="https://cdn.plot.ly/plotly-2.35.2.min.js"></script>
  <style>
    body {{ font-family: Arial, sans-serif; margin: 20px; background: #f7f8fb; color: #222; }}
    .card {{ background: white; padding: 14px; border-radius: 12px;
      box-shadow: 0 1px 4px rgba(0,0,0,.08); margin-bottom: 14px; }}
  </style>
</head>
<body>
  <h1>Credit Dashboard (LLM-generated)</h1>
  <div id="chartA" class="card" style="height:420px;"></div>
  <div id="chartB" class="card" style="height:420px;"></div>
  <div id="chartC" class="card" style="height:420px;"></div>

  <script>
    const payload = {payload_json};
    const containers = {{
      chartA: "chartA",
      chartB: "chartB",
      chartC: "chartC"
    }};
  </script>

  <script>
{safe_code}
  </script>

  <script>
    (async () => {{
      try {{
        if (typeof renderDashboard !== "function") {{
          throw new Error(
            "chart_code must define async function renderDashboard(payload, Plotly, containers)"
          );
        }}
        await renderDashboard(payload, Plotly, containers);
      }} catch (e) {{
        const msg = "Dashboard render error: " + String(e && e.message ? e.message : e);
        document.body.insertAdjacentHTML("beforeend", "<pre style=\\"color:#b91c1c;\\">" + msg + "</pre>");
      }}
    }})();
  </script>
</body>
</html>"""

    def _strip_markdown_fences(self, code: str) -> str:
        if code.startswith("```"):
            lines = code.splitlines()
            if lines and lines[0].startswith("```"):
                lines = lines[1:]
            if lines and lines[-1].strip() == "```":
                lines = lines[:-1]
            return "\n".join(lines).strip()
        return code
    def _validate_js_code(self, code: str) -> list[str]:
        errors: list[str] = []

        if len(code) > 50000:
            errors.append("chart_code is too long (>50000 chars)")

        if "renderDashboard" not in code:
            errors.append("chart_code must define renderDashboard referencing payload, Plotly, containers")

        plot_calls = code.count("Plotly.newPlot(")
        if plot_calls < 2:
            errors.append("chart_code must contain at least 2 Plotly.newPlot(...) calls")

        banned_patterns = [
            r"\beval\s*\(",
            r"\bFunction\s*\(",
            r"\bfetch\s*\(",
            r"\bXMLHttpRequest\b",
            r"\bdocument\.cookie\b",
            r"\blocalStorage\b",
            r"\bsessionStorage\b",
            r"\bwindow\.location\b",
            r"\bimport\s*\(",
            r"\brequire\s*\(",
            r"\bprocess\.",
        ]
        for pattern in banned_patterns:
            if re.search(pattern, code):
                errors.append(f"disallowed pattern: {pattern}")

        return errors

    def _check_js_syntax(self, code: str) -> tuple[bool, str]:
        try:
            with tempfile.NamedTemporaryFile("w", suffix=".mjs", delete=False, encoding="utf-8") as tmp:
                tmp.write(code)
                tmp_path = Path(tmp.name)
            result = subprocess.run(
                ["node", "--check", str(tmp_path)],
                capture_output=True,
                text=True,
                timeout=12,
                check=False,
            )
            try:
                tmp_path.unlink(missing_ok=True)
            except OSError:
                pass

            if result.returncode == 0:
                return True, ""
            err = (result.stderr or result.stdout or "node --check error").strip()
            return False, err
        except FileNotFoundError:
            return True, ""
        except Exception as exc:
            return False, str(exc)

    async def _upload_file(self, file_path: Path) -> None:
        if not file_path.exists():
            raise FileNotFoundError(f"File not found: {file_path}")

        with file_path.open("rb") as f:
            async for db in get_session():
                current_user = await get_user_by_id(db, self.user_id)
                await upload_user_file(
                    file=UploadFile(filename=file_path.name, file=f, size=file_path.stat().st_size),
                    session=db,
                    current_user=current_user,
                    storage_service=get_storage_service(),
                    settings_service=get_settings_service(),
                )
                break

    def _load_rows(self, db_path: Path) -> list[dict]:
        query = """
            SELECT *
            FROM credit_product_snapshots
            ORDER BY COALESCE(created_at, generated_at) ASC, id ASC
            LIMIT 2000
        """
        with sqlite3.connect(db_path) as conn:
            conn.row_factory = sqlite3.Row
            rows = conn.execute(query).fetchall()
        return [dict(r) for r in rows]

    def _sqlite_path(self, url: str) -> Path:
        raw = (url or "").strip()
        if raw.startswith("sqlite:///"):
            return Path(raw.replace("sqlite:///", "", 1))
        return Path(raw)

    def _normalized_filename(self, raw_name: str | None) -> str:
        filename = (raw_name or "credit_dashboard_step10.html").strip() or "credit_dashboard_step10.html"
        if not filename.lower().endswith(".html"):
            filename += ".html"
        return re.sub(r"[^a-zA-Z0-9._-]", "_", filename)

    def _resolve_output_path(self, filename: str) -> Path:
        flow_id = getattr(self, "flow_id", None)
        safe_flow = str(flow_id).strip().replace("/", "_") if flow_id else ""
        base_dir = Path("/tmp")
        target_dir = base_dir / safe_flow if safe_flow else base_dir
        target_dir.mkdir(parents=True, exist_ok=True)
        return target_dir / filename

    def _normalize_cell(self, value):
        if not isinstance(value, str):
            return value
        text = value.strip()
        if not text:
            return text

        # Try decoding values that were json-dumped before writing to DB.
        try:
            decoded = json.loads(text)
            if isinstance(decoded, (str, int, float, bool)) or decoded is None:
                return decoded
        except Exception:
            pass

        if len(text) >= 2 and ((text[0] == '"' and text[-1] == '"') or (text[0] == "'" and text[-1] == "'")):
            return text[1:-1]
        return text

    def _extract_percent(self, value: str | None):
        if value is None:
            return None
        match = re.search(r"(\d+(?:[.,]\d+)?)", str(value))
        return float(match.group(1).replace(",", ".")) if match else None

    def _extract_number(self, value: str | None):
        if value is None:
            return None
        match = re.search(r"(\d+)", str(value).replace(" ", ""))
        return float(match.group(1)) if match else None

    def _result(self, status: str, errors: list[str] | None = None) -> Data:
        payload = {"status": status, "errors": errors or []}
        self.status = payload
        return Data(data={"text": json.dumps(payload, ensure_ascii=False), **payload})
